#include "controller.h"

/* Constants */
#define CONTROLLER_LEVEL_LOW_THRESHOLD 30
#define CONTROLLER_LEVEL_HIGH_THRESHOLD 80
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

/* State machine constants */
#define STATE_SAFE_OFF    0
#define STATE_PUMPING     1
#define STATE_HOLDING     2

typedef enum {
    CONTROLLER_INPUT_NONE = 0,
    CONTROLLER_INPUT_LEVEL,
    CONTROLLER_INPUT_SENSOR_TIMEOUT,
    CONTROLLER_INPUT_INVALID_LEVEL,
} controller_input_kind_t;

typedef enum {
    CONTROLLER_STATE_SAFE_OFF = 0,
    CONTROLLER_STATE_PUMPING,
    CONTROLLER_STATE_HOLDING,
} controller_state_t;

/* Controller output structure */
typedef struct {
    bool pump_on;
    controller_state_t state;
    const char *state_name;
    bool changed;
    bool timed_out;
} controller_output_t;

/* Input structure */
typedef struct {
    controller_input_kind_t kind;
    int level;
    uint32_t now_ms;
} controller_input_t;

/* Controller state machine */
typedef struct {
    bool pump_on;
    controller_state_t state;
    bool has_valid_sensor;
    int last_level;
    uint32_t last_valid_sensor_ms;
    bool timed_out;
    uint32_t timeout_remaining_ms;  /* Time remaining before timeout expires */
} controller_t;

/* Helper functions */
static void controller_set_safe_off(controller_t *controller)
{
    controller->pump_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
    controller->has_valid_sensor = false;
    controller->timeout_remaining_ms = 0U;
}

/* Initialize controller - sets default state to OFF */
void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    /* Default behavior: pump off before any valid sensor input */
    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_level = 0;
    controller->last_valid_sensor_ms = 0U;
}

/* Process a single controller step */
controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .pump_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = "STATE SAFE_OFF",
        .changed = false,
        .timed_out = false,
    };

    /* Handle NULL controller */
    if (controller == NULL) {
        return output;
    }

    /* Track previous state for change detection */
    bool previous_pump_on = controller->pump_on;
    bool previous_state = controller->state;

    /* Check timeout first - fail safe immediately on loss of valid input */
    if (controller->timed_out) {
        output.pump_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = "STATE SAFE_OFF";
        output.changed = (previous_pump_on != controller->pump_on) || (previous_state != controller->state);
        return output;
    }

    /* Check if we need to reset timeout */
    if (!controller->has_valid_sensor && input.kind == CONTROLLER_INPUT_NONE) {
        /* No new valid sensor - reset timeout, stay in current state */
        controller->timed_out = false;
        controller->timeout_remaining_ms = 0U;
        return output;
    }

    if (input.kind == CONTROLLER_INPUT_LEVEL) {
        /* Update state machine on new level input */
        controller->has_valid_sensor = true;
        controller->last_level = input.level;
        controller->last_valid_sensor_ms = input.now_ms;

        /* Check for timeout condition - fail safe to OFF if no valid sensor and timeout exceeded */
        if (!controller->has_valid_sensor && controller->timed_out) {
            controller->timeout_remaining_ms = 0U;
            controller_set_safe_off(controller);
            return output;
        }

        /* Check level threshold for state transition */
        if (input.level < CONTROLLER_LEVEL_LOW_THRESHOLD) {
            /* Pump ON - low level triggers activation */
            controller->pump_on = true;
            controller->state = CONTROLLER_STATE_PUMPING;
        } else if (input.level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
            /* Pump OFF - high level triggers shutdown */
            controller->pump_on = false;
            controller->state = CONTROLLER_STATE_SAFE_OFF;
        } else {
            /* Mid-band level - hold previous safe output */
            /* No change to state or pump_on */
        }

    } else if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        /* Timeout condition - fail safe to OFF */
        controller->pump_on = false;
        controller->state = CONTROLLER_STATE_SAFE_OFF;
        output.pump_on = controller->pump_on;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (previous_pump_on != controller->pump_on) || (previous_state != controller->state);
        return output;

    } else if (input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        /* Malformed input - fail safe to OFF */
        controller->pump_on = false;
        controller->state = CONTROLLER_STATE_SAFE_OFF;
        output.pump_on = controller->pump_on;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (previous_pump_on != controller->pump_on) || (previous_state != controller->state);
        return output;
    }

    /* Normal case: no change to state or pump */
    output.pump_on = controller->pump_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_pump_on != controller->pump_on) || (previous_state != controller->state);

    return output;
}

/* Get current state name */
const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_SAFE_OFF:
        return "STATE SAFE_OFF";
    case CONTROLLER_STATE_PUMPING:
        return "STATE PUMPING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    default:
        return "STATE SAFE_OFF";
    }
}

/* Get current pump state from state */
static inline bool controller_get_pump_state(controller_t *controller) {
    if (controller->state == CONTROLLER_STATE_SAFE_OFF) {
        return false;
    }
    switch (controller->state) {
    case CONTROLLER_STATE_PUMPING:
        return true;
    case CONTROLLER_STATE_HOLDING:
        return false;
    default:
        return false;
    }
}

/* Reset controller to safe off state */
static void controller_reset_safe_off(controller_t *controller)
{
    controller->pump_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
    controller->has_valid_sensor = false;
    controller->timeout_remaining_ms = 0U;
}

/* Reset controller to pump state */
static void controller_reset_pumping(controller_t *controller)
{
    controller->pump_on = true;
    controller->state = CONTROLLER_STATE_PUMPING;
    controller->has_valid_sensor = false;
    controller->timeout_remaining_ms = 0U;
}

/* Reset controller to holding state */
static void controller_reset_holding(controller_t *controller)
{
    controller->pump_on = false;
    controller->state = CONTROLLER_STATE_HOLDING;
    controller->has_valid_sensor = false;
    controller->timeout_remaining_ms = 0U;
}

/* Reset to safe off with timeout reset */
static void controller_reset_safe_with_timeout(controller_t *controller)
{
    controller->pump_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
    controller->has_valid_sensor = false;
    controller->timeout_remaining_ms = 0U;
}

/* Reset to pump with timeout reset */
static void controller_reset_pumping_with_timeout(controller_t *controller)
{
    controller->pump_on = true;
    controller->state = CONTROLLER_STATE_PUMPING;
    controller->has_valid_sensor = false;
    controller->timeout_remaining_ms = 0U;
}

/* Reset to holding with timeout reset */
static void controller_reset_holding_with_timeout(controller_t *controller)
{
    controller->pump_on = false;
    controller->state = CONTROLLER_STATE_HOLDING;
    controller->has_valid_sensor = false;
    controller->timeout_remaining_ms = 0U;
}

