typedef enum {
    CONTROLLER_STATE_SAFE_OFF = 0,
    CONTROLLER_STATE_PUMPING,
    CONTROLLER_STATE_HOLDING,
} controller_state_t;

/* Controller structure - implements the tank fill/drain control policy */
typedef struct {
    bool pump_on;
    controller_state_t state;
    bool has_valid_sensor;
    int last_level;
    uint32_t last_valid_sensor_ms;
    bool timed_out;
} controller_t;

